package fileutil

import (
	"bufio"
	"errors"
	"io"
	"os"
	"unicode/utf8"
)

type FileReader struct {
	file     *os.File
	reader   *bufio.Reader
	buffer   []byte
	encoding string
}

func NewFileReader(filePath string) (*FileReader, error) {
	file, err := os.Open(filePath)
	if err != nil {
		return nil, err
	}

	reader := bufio.NewReader(file)
	buffer := make([]byte, 4096) // Default buffer size

	return &FileReader{
		file:     file,
		reader:   reader,
		buffer:   buffer,
		encoding: "utf-8", // Default encoding
	}, nil
}

func (fr *FileReader) ReadAllLines() ([]string, error) {
	var lines []string

	for {
		line, err := fr.reader.ReadString('\n')
		if err != nil {
			if err == io.EOF {
				if line != "" {
					lines = append(lines, line)
				}
				break
			}
			return nil, err
		}

		// Detect encoding if not UTF-8
		if !utf8.ValidString(line) {
			return nil, errors.New("corrupted data: invalid UTF-8 encoding")
		}

		lines = append(lines, line)
	}

	return lines, nil
}

func (fr *FileReader) CloseHandle() error {
	if fr.file == nil {
		return nil
	}
	err := fr.file.Close()
	fr.file = nil
	fr.reader = nil
	fr.buffer = nil
	return err
}
