pub mod geometry {
    use std::f64::consts::PI;

    #[derive(Debug)]
    pub struct Circle {
        x: f64,
        y: f64,
        radius: f64,
    }

    impl Circle {
        pub fn new(x: f64, y: f64, radius: f64) -> Result<Self, String> {
            if radius <= 0.0 {
                return Err("Radius must be positive".to_string());
            }
            Ok(Self { x, y, radius })
        }

        pub fn calculate_area(&self, precision: usize) -> f64 {
            let area = PI * self.radius.powi(2);
            let scale = 10_f64.powi(precision as i32);
            (area * scale).round() / scale
        }

        pub fn set_radius(&mut self, radius: f64) -> Result<(), String> {
            if radius <= 0.0 {
                return Err("Radius must be positive".to_string());
            }
            self.radius = radius;
            Ok(())
        }

        pub fn collides_with(&self, other: &Circle) -> bool {
            let dx = self.x - other.x;
            let dy = self.y - other.y;
            let distance_squared = dx.powi(2) + dy.powi(2);
            let radius_sum = self.radius + other.radius;
            distance_squared <= radius_sum.powi(2)
        }
    }
}
