const std = @import("std");
const mem = std.mem;
const Allocator = std.mem.Allocator;

const IniError = error{
    invalid_syntax_error,
    duplicate_key_error,
    invalid_escape_sequence_error,
    invalid_type_coercion_error,
    line_continuation_error,
};

const Value = union(enum) {
    string: []const u8,
    integer: i64,
    boolean: bool,
};

const KeyValuePair = struct {
    key: []const u8,
    value: Value,
};

const IniSection = struct {
    name: []const u8,
    pairs: std.StringHashMap(KeyValuePair),
    allocator: Allocator,

    pub fn init(allocator: Allocator, name: []const u8) IniSection {
        return .{
            .name = name,
            .pairs = std.StringHashMap(KeyValuePair).init(allocator),
            .allocator = allocator,
        };
    }

    pub fn deinit(self: *IniSection) void {
        var it = self.pairs.iterator();
        while (it.next()) |entry| {
            self.allocator.free(entry.key_ptr.*);
            if (entry.value_ptr.value == .string) {
                self.allocator.free(entry.value_ptr.value.string);
            }
        }
        self.pairs.deinit();
    }

    pub fn getValue(self: *const IniSection, key: []const u8, comptime T: type) IniError!T {
        const pair = self.pairs.get(key) orelse return error.invalid_syntax_error;
        return switch (pair.value) {
            .string => |s| try parseStringAsType(s, T),
            .integer => |i| if (T == i64) i else return error.invalid_type_coercion_error,
            .boolean => |b| if (T == bool) b else return error.invalid_type_coercion_error,
        };
    }

    pub fn addKeyValuePair(self: *IniSection, key: []const u8, value: Value, resolve_duplicates: bool) IniError!void {
        const owned_key = try self.allocator.dupe(u8, key);
        errdefer self.allocator.free(owned_key);

        const owned_value = switch (value) {
            .string => |s| blk: {
                const owned = try self.allocator.dupe(u8, s);
                break :blk Value{ .string = owned };
            },
            else => value,
        };

        if (self.pairs.get(key)) |_| {
            if (!resolve_duplicates) return error.duplicate_key_error;
            var old_pair = self.pairs.fetchRemove(key).?.value;
            if (old_pair.value == .string) {
                self.allocator.free(old_pair.value.string);
            }
            self.allocator.free(old_pair.key);
        }

        try self.pairs.put(owned_key, .{ .key = owned_key, .value = owned_value });
    }

    fn parseStringAsType(s: []const u8, comptime T: type) IniError!T {
        return switch (T) {
            i64 => std.fmt.parseInt(i64, s, 10) catch return error.invalid_type_coercion_error,
            bool => parseBool(s),
            []const u8 => s,
            else => error.invalid_type_coercion_error,
        };
    }

    fn parseBool(s: []const u8) IniError!bool {
        if (mem.eql(u8, s, "true") or mem.eql(u8, s, "yes") or mem.eql(u8, s, "on")) {
            return true;
        } else if (mem.eql(u8, s, "false") or mem.eql(u8, s, "no") or mem.eql(u8, s, "off")) {
            return false;
        }
        return error.invalid_type_coercion_error;
    }
};

const IniDocument = struct {
    sections: std.StringHashMap(*IniSection),
    allocator: Allocator,

    pub fn init(allocator: Allocator) IniDocument {
        return .{
            .sections = std.StringHashMap(*IniSection).init(allocator),
            .allocator = allocator,
        };
    }

    pub fn deinit(self: *IniDocument) void {
        var it = self.sections.iterator();
        while (it.next()) |entry| {
            entry.value_ptr.*.deinit();
            self.allocator.destroy(entry.value_ptr.*);
        }
        self.sections.deinit();
    }

    pub fn parse(self: *IniDocument, text: []const u8) IniError!void {
        var lines = mem.splitSequence(u8, text, "\n");
        var current_section: ?*IniSection = null;
        var line_number: usize = 0;

        while (lines.next()) |line| {
            line_number += 1;
            const trimmed = mem.trim(u8, line, " \t\r");
            if (trimmed.len == 0 or trimmed[0] == ';') continue;

            if (trimmed[0] == '[') {
                if (trimmed[trimmed.len - 1] != ']') return error.invalid_syntax_error;
                const section_name = mem.trim(u8, trimmed[1 .. trimmed.len - 1], " \t");
                if (self.sections.get(section_name)) |_| return error.duplicate_key_error;

                var section = try self.allocator.create(IniSection);
                section.* = IniSection.init(self.allocator, section_name);
                try self.sections.put(section_name, section);
                current_section = section;
            } else {
                if (current_section == null) return error.invalid_syntax_error;
                try parseKeyValuePair(current_section.?, trimmed, line_number);
            }
        }
    }

    fn parseKeyValuePair(section: *IniSection, line: []const u8, line_number: usize) IniError!void {
        var parts = mem.splitSequence(u8, line, "=");
        const key = mem.trim(u8, parts.first(), " \t");
        if (key.len == 0) return error.invalid_syntax_error;

        var value_str = if (parts.next()) |v| mem.trim(u8, v, " \t") else "";
        var value = try parseValue(value_str);
        try section.addKeyValuePair(key, value, false);
    }

    fn parseValue(s: []const u8) IniError!Value {
        if (s.len == 0) return Value{ .string = "" };

        if (s[0] == '"') {
            if (s[s.len - 1] != '"') return error.invalid_syntax_error;
            var unescaped = try unescapeString(s[1 .. s.len - 1]);
            return Value{ .string = unescaped };
        }

        if (std.fmt.parseInt(i64, s, 10)) |i| {
            return Value{ .integer = i };
        } else |_| {}

        if (parseBool(s)) |b| {
            return Value{ .boolean = b };
        } else |_| {}

        return Value{ .string = s };
    }

    fn unescapeString(s: []const u8) IniError![]const u8 {
        // Implement escape sequence handling here
        return s;
    }
};
