#include <queue>
#include <mutex>
#include <condition_variable>
#include <chrono>
#include <stdexcept>
#include <utility>

template<typename T, typename Allocator = std::allocator<T>>
class ThreadSafeQueue {
public:
    explicit ThreadSafeQueue(size_t maxSize, const Allocator& alloc = Allocator())
        : max_size_(maxSize), allocator_(alloc) {}

    bool pushBack(const T& item, std::chrono::milliseconds timeout) {
        std::unique_lock<std::mutex> lock(mutex_);
        if (!not_full_.wait_for(lock, timeout, [this]() { return queue_.size() < max_size_; })) {
            return false;
        }
        queue_.push(item);
        not_empty_.notify_one();
        return true;
    }

    bool popFront(T& item) {
        std::unique_lock<std::mutex> lock(mutex_);
        not_empty_.wait(lock, [this]() { return !queue_.empty(); });
        item = std::move(queue_.front());
        queue_.pop();
        not_full_.notify_one();
        return true;
    }

    size_t size() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return queue_.size();
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return queue_.empty();
    }

private:
    mutable std::mutex mutex_;
    std::condition_variable not_empty_;
    std::condition_variable not_full_;
    std::queue<T, std::deque<T, Allocator>> queue_;
    size_t max_size_;
    Allocator allocator_;
};
