        var eventData = new
        {
            ProcessId = processId,
            StartupArguments = startupArguments,
            Timestamp = DateTime.UtcNow
        };

        if (_diagnosticSource.IsEnabled("ProcessStarted"))
        {
            _diagnosticSource.Write("ProcessStarted", eventData);
        }

        ProcessStarted?.Invoke(this, new ProcessStartedEventArgs(processId, startupArguments));
    }

    public void OnProcessExited(int processId, int exitCode, long memoryUsage)
    {
        var eventData = new
        {
            ProcessId = processId,
            ExitCode = exitCode,
            MemoryUsage = memoryUsage,
            Timestamp = DateTime.UtcNow
        };

        if (_diagnosticSource.IsEnabled("ProcessExited"))
        {
            _diagnosticSource.Write("ProcessExited", eventData);
        }

        ProcessExited?.Invoke(this, new ProcessExitedEventArgs(processId, exitCode, memoryUsage));
    }
}

