const std = @import("std");
const builtin = @import("builtin");
const crypto = std.crypto;
const endian = std.builtin.Endian;

pub const PacketError = error{
    invalid_checksum_error,
    malformed_packet_error,
    unsupported_ip_version_error,
};

pub const PacketDecoder = struct {
    buffer: []u8,
    offset: usize = 0,
    endianness: endian.Endian,

    pub fn init(buffer: []u8, endianness: endian.Endian) PacketDecoder {
        return PacketDecoder{
            .buffer = buffer,
            .endianness = endianness,
        };
    }

    pub fn readHeader(self: *PacketDecoder) !u32 {
        if (self.buffer.len < 4) return PacketError.malformed_packet_error;
        const header = std.mem.readInt(u32, self.buffer[0..4], self.endianness);
        self.offset += 4;
        return header;
    }

    pub fn validateChecksum(self: *PacketDecoder) !void {
        if (self.buffer.len < 4) return PacketError.malformed_packet_error;
        const checksum = std.mem.readInt(u32, self.buffer[0..4], self.endianness);
        const computed_checksum = crc32(self.buffer[4..]);
        if (checksum != computed_checksum) {
            return PacketError.invalid_checksum_error;
        }
    }

    pub fn negotiateIpVersion(self: *PacketDecoder) !u8 {
        const version_byte = try self.readHeader();
        const version = (version_byte >> 28) & 0xF;
        if (version != 4 and version != 6) {
            return PacketError.unsupported_ip_version_error;
        }
        return @intCast(u8, version);
    }

    pub fn quarantineMalformedPacket(self: *PacketDecoder) void {
        // Logic to quarantine malformed packets (e.g., log, discard, or store)
        // Implementation depends on specific quarantine requirements
    }

    fn crc32(data: []const u8) u32 {
        var hasher = crypto.hash.Crc32.init();
        hasher.update(data);
        return hasher.final();
    }
};
