const std = @import("std");
const math = std.math;

pub const PixelMatrix = struct {
    width: usize,
    height: usize,
    depth: u16, // 12 or 16-bit
    data: []u16,
    allocator: std.mem.Allocator,

    pub fn init(width: usize, height: usize, depth: u16, allocator: std.mem.Allocator) !*PixelMatrix {
        const data = try allocator.alloc(u16, width * height);
        var matrix = try allocator.create(PixelMatrix);
        matrix.* = .{
            .width = width,
            .height = height,
            .depth = depth,
            .data = data,
            .allocator = allocator,
        };
        return matrix;
    }

    pub fn deinit(self: *PixelMatrix) void {
        self.allocator.free(self.data);
        self.allocator.destroy(self);
    }

    pub fn convertToGrayscale(self: *PixelMatrix) void {
        const max_hounsfield: u16 = if (self.depth == 12) 4095 else 65535;
        for (self.data) |*pixel| {
            const scaled = (@as(f32, @floatFromInt(pixel.*)) / @as(f32, @floatFromInt(max_hounsfield))) * 255.0;
            pixel.* = @intFromFloat(math.clamp(scaled, 0.0, 255.0));
        }
    }

    pub fn applyKernel(self: *PixelMatrix, kernel: []const []const i16, is_sobel: bool) !void {
        if (kernel.len == 0 or kernel[0].len == 0) return error.InvalidKernelError;

        const edge = kernel.len / 2;
        var output = try self.allocator.alloc(u16, self.width * self.height);
        defer self.allocator.free(output);

        for (0..self.height) |y| {
            for (0..self.width) |x| {
                var sum_x: i32 = 0;
                var sum_y: i32 = 0;

                for (0..kernel.len) |ky| {
                    for (0..kernel[ky].len) |kx| {
                        const px = @as(i32, @intCast(x)) + @as(i32, @intCast(kx)) - @as(i32, @intCast(edge));
                        const py = @as(i32, @intCast(y)) + @as(i32, @intCast(ky)) - @as(i32, @intCast(edge));

                        if (px >= 0 and px < self.width and py >= 0 and py < self.height) {
                            const val = self.data[py * self.width + px];
                            sum_x += @as(i32, @intCast(kernel[ky][kx])) * @as(i32, @intCast(val));
                            if (is_sobel) {
                                sum_y += @as(i32, @intCast(kernel[kx][ky])) * @as(i32, @intCast(val));
                            }
                        }
                    }
                }

                const magnitude = if (is_sobel) 
                    math.sqrt(@as(f32, @floatFromInt(sum_x * sum_x + sum_y * sum_y)))
                else
                    @abs(sum_x);

                output[y * self.width + x] = @intFromFloat(math.clamp(magnitude, 0.0, if (self.depth == 12) 4095.0 else 65535.0));
            }
        }

        @memcpy(self.data, output);
    }

    pub fn anisotropicDiffusion(self: *PixelMatrix, iterations: usize, lambda: f32, k: f32) !void {
        var temp = try self.allocator.alloc(u16, self.width * self.height);
        defer self.allocator.free(temp);

        for (0..iterations) |_| {
            for (1..self.height - 1) |y| {
                for (1..self.width - 1) |x| {
                    const idx = y * self.width + x;
                    const center = @as(f32, @floatFromInt(self.data[idx]));

                    const north = @as(f32, @floatFromInt(self.data[(y - 1) * self.width + x]));
                    const south = @as(f32, @floatFromInt(self.data[(y + 1) * self.width + x]));
                    const east = @as(f32, @floatFromInt(self.data[y * self.width + (x + 1)]));
                    const west = @as(f32, @floatFromInt(self.data[y * self.width + (x - 1)]));

                    const cN = math.exp(-1.0 * math.pow(f32, (north - center) / k, 2.0));
                    const cS = math.exp(-1.0 * math.pow(f32, (south - center) / k, 2.0));
                    const cE = math.exp(-1.0 * math.pow(f32, (east - center) / k, 2.0));
                    const cW = math.exp(-1.0 * math.pow(f32, (west - center) / k, 2.0));

                    const new_val = center + lambda * (
                        cN * (north - center) + 
                        cS * (south - center) + 
                        cE * (east - center) + 
                        cW * (west - center)
                    );

                    temp[idx] = @intFromFloat(math.clamp(new_val, 0.0, if (self.depth == 12) 4095.0 else 65535.0));
                }
            }
            @memcpy(self.data, temp);
        }
    }
};
