import java.util.*;
import java.util.concurrent.*;
import java.net.http.*;
import java.net.URI;
import java.time.Duration;
import java.util.function.*;
import java.util.zip.*;
import java.io.*;

public class NetworkRequestHandler {
    private final HttpClient http_client;
    private final CircuitBreaker circuit_breaker;
    private final MetricsCollector metrics_collector;
    private final ExecutorService executor_service;

    public NetworkRequestHandler() {
        this.http_client = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_2)
            .connectTimeout(Duration.ofSeconds(10))
            .executor(Executors.newFixedThreadPool(10))
            .build();
        this.circuit_breaker = new CircuitBreaker();
        this.metrics_collector = new MetricsCollector();
        this.executor_service = Executors.newCachedThreadPool();
    }

    public CompletableFuture<List<HttpResponse<String>>> batchAsyncRequests(List<HttpRequest> requests) {
        List<CompletableFuture<HttpResponse<String>>> futures = new ArrayList<>();
        for (HttpRequest request : requests) {
            futures.add(sendAsyncRequest(request));
        }
        return CompletableFuture.allOf(futures.toArray(new CompletableFuture[0]))
            .thenApply(v -> futures.stream()
                .map(CompletableFuture::join)
                .toList());
    }

    private CompletableFuture<HttpResponse<String>> sendAsyncRequest(HttpRequest request) {
        if (!circuit_breaker.allowRequest()) {
            return CompletableFuture.failedFuture(new CircuitBreakerOpenException());
        }
        long start_time = System.currentTimeMillis();
        return http_client.sendAsync(request, HttpResponse.BodyHandlers.ofString())
            .handle((response, exception) -> {
                metrics_collector.recordLatency(System.currentTimeMillis() - start_time);
                if (exception != null) {
                    circuit_breaker.recordFailure();
                    throw new CompletionException(exception);
                }
                circuit_breaker.recordSuccess();
                return response;
            });
    }

    public HttpResponse<String> sendWithRetry(HttpRequest request, int max_retries) throws Exception {
        int retry_count = 0;
        long backoff_time = 1000;
        while (true) {
            try {
                return sendRequest(request);
            } catch (Exception e) {
                if (retry_count >= max_retries) throw e;
                retry_count++;
                Thread.sleep(backoff_time);
                backoff_time *= 2;
            }
        }
    }

    private HttpResponse<String> sendRequest(HttpRequest request) throws Exception {
        if (!circuit_breaker.allowRequest()) {
            throw new CircuitBreakerOpenException();
        }
        long start_time = System.currentTimeMillis();
        try {
            HttpResponse<String> response = http_client.send(request, HttpResponse.BodyHandlers.ofString());
            circuit_breaker.recordSuccess();
            metrics_collector.recordLatency(System.currentTimeMillis() - start_time);
            return response;
        } catch (Exception e) {
            circuit_breaker.recordFailure();
            metrics_collector.recordLatency(System.currentTimeMillis() - start_time);
            throw e;
        }
    }

    public HttpRequest.Builder createRequestBuilder(String url, Map<String, String> headers) {
        HttpRequest.Builder builder = HttpRequest.newBuilder()
            .uri(URI.create(url));
        headers.forEach((key, value) -> builder.header(key, value));
        return builder;
    }

    public byte[] compressPayload(byte[] payload) throws IOException {
        ByteArrayOutputStream byte_array_stream = new ByteArrayOutputStream();
        try (GZIPOutputStream gzip_stream = new GZIPOutputStream(byte_array_stream)) {
            gzip_stream.write(payload);
        }
        return byte_array_stream.toByteArray();
    }

    public byte[] decompressPayload(byte[] compressed_payload) throws IOException {
        ByteArrayOutputStream byte_array_stream = new ByteArrayOutputStream();
        try (GZIPInputStream gzip_stream = new GZIPInputStream(new ByteArrayInputStream(compressed_payload))) {
            byte[] buffer = new byte[1024];
            int len;
            while ((len = gzip_stream.read(buffer)) > 0) {
                byte_array_stream.write(buffer, 0, len);
            }
        }
        return byte_array_stream.toByteArray();
    }

    private static class CircuitBreaker {
        private static final int MAX_FAILURES = 5;
        private static final long RESET_TIMEOUT = 60000;
        private int failure_count = 0;
        private long last_failure_time = 0;
        private boolean is_open = false;

        public synchronized boolean allowRequest() {
            if (is_open) {
                if (System.currentTimeMillis() - last_failure_time > RESET_TIMEOUT) {
                    is_open = false;
                    failure_count = 0;
                    return true;
                }
                return false;
            }
            return true;
        }

        public synchronized void recordFailure() {
            failure_count++;
            if (failure_count >= MAX_FAILURES) {
                is_open = true;
                last_failure_time = System.currentTimeMillis();
            }
        }

        public synchronized void recordSuccess() {
            failure_count = 0;
        }
    }

    private static class MetricsCollector {
        private final List<Long> latency_records = new ArrayList<>();

        public synchronized void recordLatency(long latency) {
            latency_records.add(latency);
        }

        public synchronized List<Long> getLatencyRecords() {
            return new ArrayList<>(latency_records);
        }
    }

    private static class CircuitBreakerOpenException extends RuntimeException {
        public CircuitBreakerOpenException() {
            super("Circuit breaker is open. Requests are blocked.");
        }
    }
}
