class WebSocketManager {
  constructor(config) {
    this.config = {
      'endpoint-url': config['endpoint-url'] || 'wss://api.stockplatform.com/ws',
      'reconnect-attempts': config['reconnect-attempts'] || 5,
      'heartbeat-interval': config['heartbeat-interval'] || 30000,
      'backoff-base': config['backoff-base'] || 1000,
      'backoff-max': config['backoff-max'] || 30000,
      'compression-enabled': config['compression-enabled'] || true
    };
    this.socket = null;
    this.subscriptions = new Set();
    this.reconnectCount = 0;
    this.heartbeatIntervalId = null;
    this.isConnected = false;
    this.protobuf = require('protocol-buffers');
    this.ajv = new (require('ajv'))();
    this.schema = require('./schema.json');
  }

  connect() {
    this.socket = new WebSocket(this.config['endpoint-url']);

    this.socket.onopen = () => {
      this.isConnected = true;
      this.reconnectCount = 0;
      this.startHeartbeat();
      this.emit('connectionEstablished');
    };

    this.socket.onmessage = (event) => {
      try {
        const message = this.config['compression-enabled'] 
          ? this.protobuf.decode(event.data) 
          : JSON.parse(event.data);

        if (this.validatePayload(message)) {
          this.emit('messageReceived', message);
        } else {
          this.emit('invalidPayload', message);
        }
      } catch (error) {
        this.emit('messageError', error);
      }
    };

    this.socket.onclose = () => {
      this.isConnected = false;
      this.stopHeartbeat();
      this.attemptReconnect();
    };

    this.socket.onerror = (error) => {
      this.emit('connectionError', error);
    };
  }

  startHeartbeat() {
    this.heartbeatIntervalId = setInterval(() => {
      this.sendMessage({ type: 'heartbeat' });
    }, this.config['heartbeat-interval']);
  }

  stopHeartbeat() {
    if (this.heartbeatIntervalId) {
      clearInterval(this.heartbeatIntervalId);
      this.heartbeatIntervalId = null;
    }
  }

  attemptReconnect() {
    if (this.reconnectCount < this.config['reconnect-attempts']) {
      const jitter = Math.random() * 1000;
      const delay = Math.min(
        this.config['backoff-base'] * Math.pow(2, this.reconnectCount) + jitter,
        this.config['backoff-max']
      );

      setTimeout(() => {
        this.reconnectCount++;
        this.connect();
      }, delay);
    } else {
      this.emit('connectionFailed');
    }
  }

  sendMessage(message) {
    if (this.isConnected) {
      const payload = this.config['compression-enabled']
        ? this.protobuf.encode(message)
        : JSON.stringify(message);
      this.socket.send(payload);
    }
  }

  subscribe(feedId) {
    this.subscriptions.add(feedId);
    this.sendMessage({ type: 'subscribe', feedId });
  }

  unsubscribe(feedId) {
    this.subscriptions.delete(feedId);
    this.sendMessage({ type: 'unsubscribe', feedId });
  }

  validatePayload(payload) {
    return this.ajv.validate(this.schema, payload);
  }

  on(event, callback) {
    if (!this.eventListeners) this.eventListeners = {};
    if (!this.eventListeners[event]) this.eventListeners[event] = [];
    this.eventListeners[event].push(callback);
  }

  emit(event, ...args) {
    if (this.eventListeners && this.eventListeners[event]) {
      this.eventListeners[event].forEach(callback => callback(...args));
    }
  }

  close() {
    if (this.socket) {
      this.socket.close();
      this.socket = null;
    }
    this.stopHeartbeat();
    this.isConnected = false;
  }
}
