package main

import (
	"compress/gzip"
	"crypto/tls"
	"fmt"
	"io"
	"log"
	"os"
	"path/filepath"
	"regexp"
	"sync"
	"time"

	"github.com/aws/aws-sdk-go/aws"
	"github.com/aws/aws-sdk-go/aws/session"
	"github.com/aws/aws-sdk-go/service/s3"
)

type LogAggregator struct {
	config          Config
	logQueue       chan LogEntry
	rotationTicker *time.Ticker
	mu             sync.Mutex
	currentFile    *os.File
	currentSize    int64
	s3Client       *s3.S3
}

type Config struct {
	max_file_size    int64
	rotation_period  time.Duration
	s3_bucket_name   string
	s3_region       string
	tls_cert_path   string
	tls_key_path    string
	log_dir         string
}

type LogEntry struct {
	Timestamp time.Time
	Message   string
	Metadata  map[string]string
}

func NewLogAggregator(config Config) (*LogAggregator, error) {
	sess, err := session.NewSession(&aws.Config{
		Region: aws.String(config.s3_region),
	})
	if err != nil {
		return nil, err
	}

	agg := &LogAggregator{
		config:        config,
		logQueue:     make(chan LogEntry, 1000),
		s3Client:     s3.New(sess),
		rotationTicker: time.NewTicker(config.rotation_period),
	}

	if err := os.MkdirAll(config.log_dir, 0755); err != nil {
		return nil, err
	}

	if err := agg.rotateLog(); err != nil {
		return nil, err
	}

	go agg.processLogs()
	go agg.handleRotation()

	return agg, nil
}

func (la *LogAggregator) ingestLog(message string, metadata map[string]string) {
	la.logQueue <- LogEntry{
		Timestamp: time.Now(),
		Message:   message,
		Metadata:  metadata,
	}
}

func (la *LogAggregator) filterLogs(pattern string) ([]LogEntry, error) {
	re, err := regexp.Compile(pattern)
	if err != nil {
		return nil, err
	}

	var matches []LogEntry
	for entry := range la.logQueue {
		if re.MatchString(entry.Message) {
			matches = append(matches, entry)
		}
	}
	return matches, nil
}

func (la *LogAggregator) exportToS3(batchSize int) error {
	la.mu.Lock()
	defer la.mu.Unlock()

	if err := la.currentFile.Close(); err != nil {
		return err
	}

	file, err := os.Open(la.currentFile.Name())
	if err != nil {
		return err
	}
	defer file.Close()

	pr, pw := io.Pipe()
	go func() {
		gzw := gzip.NewWriter(pw)
		if _, err := io.Copy(gzw, file); err != nil {
			pw.CloseWithError(err)
			return
		}
		gzw.Close()
		pw.Close()
	}()

	_, err = la.s3Client.PutObject(&s3.PutObjectInput{
		Bucket: aws.String(la.config.s3_bucket_name),
		Key:    aws.String(filepath.Base(la.currentFile.Name()) + ".gz"),
		Body:   pr,
	})
	return err
}

func (la *LogAggregator) rotateLog() error {
	la.mu.Lock()
	defer la.mu.Unlock()

	if la.currentFile != nil {
		if err := la.currentFile.Close(); err != nil {
			return err
		}
	}

	filename := fmt.Sprintf("%s/log_%s.log", la.config.log_dir, time.Now().Format("20060102_150405"))
	file, err := os.Create(filename)
	if err != nil {
		return err
	}

	la.currentFile = file
	la.currentSize = 0
	return nil
}

func (la *LogAggregator) processLogs() {
	for entry := range la.logQueue {
		la.mu.Lock()
		n, err := fmt.Fprintf(la.currentFile, "[%s] %s\n", entry.Timestamp.Format(time.RFC3339), entry.Message)
		if err != nil {
			log.Printf("Error writing log: %v", err)
		}
		la.currentSize += int64(n)
		la.mu.Unlock()
	}
}

func (la *LogAggregator) handleRotation() {
	for {
		select {
		case <-la.rotationTicker.C:
			if err := la.rotateLog(); err != nil {
				log.Printf("Error rotating log: %v", err)
			}
		default:
			la.mu.Lock()
			if la.currentSize >= la.config.max_file_size {
				if err := la.rotateLog(); err != nil {
					log.Printf("Error rotating log: %v", err)
				}
			}
			la.mu.Unlock()
			time.Sleep(1 * time.Second)
		}
	}
}

func (la *LogAggregator) startTLSServer() error {
	cert, err := tls.LoadX509KeyPair(la.config.tls_cert_path, la.config.tls_key_path)
	if err != nil {
		return err
	}

	config := &tls.Config{Certificates: []tls.Certificate{cert}}
	ln, err := tls.Listen("tcp", ":443", config)
	if err != nil {
		return err
	}

	go func() {
		for {
			conn, err := ln.Accept()
			if err != nil {
				log.Printf("TLS accept error: %v", err)
				continue
			}
			go la.handleTLSConnection(conn)
		}
	}()

	return nil
}

func (la *LogAggregator) handleTLSConnection(conn io.ReadWriteCloser) {
	defer conn.Close()
	// Implement your TLS connection handling logic here
