#include <opencv2/opencv.hpp>
#include <opencv2/core/cuda.hpp>
#include <opencv2/cudaimgproc.hpp>
#include <opencv2/cudawarping.hpp>
#include <thread>
#include <vector>
#include <mutex>
#include <queue>

class ImageProcessor {
private:
    cv::VideoCapture video_capture;
    cv::cuda::GpuMat gpu_frame;
    cv::cuda::GpuMat prev_frame;
    cv::cuda::GpuMat motion_mask;
    std::queue<cv::Mat> frame_queue;
    std::mutex queue_mutex;
    bool is_processing;
    std::vector<std::thread> processing_threads;

    void motionDetection() {
        cv::cuda::absdiff(gpu_frame, prev_frame, motion_mask);
        cv::cuda::threshold(motion_mask, motion_mask, 25, 255, cv::THRESH_BINARY);
    }

    void processFrames() {
        while (is_processing) {
            cv::Mat frame;
            {
                std::lock_guard<std::mutex> lock(queue_mutex);
                if (!frame_queue.empty()) {
                    frame = frame_queue.front();
                    frame_queue.pop();
                }
            }
            if (!frame.empty()) {
                gpu_frame.upload(frame);
                if (!prev_frame.empty()) {
                    motionDetection();
                }
                prev_frame = gpu_frame.clone();
            }
        }
    }

public:
    ImageProcessor() : is_processing(false) {}

    bool initializeStream(const std::string& stream_url) {
        video_capture.open(stream_url);
        return video_capture.isOpened();
    }

    void startProcessing(int num_threads = 4) {
        is_processing = true;
        for (int i = 0; i < num_threads; ++i) {
            processing_threads.emplace_back(&ImageProcessor::processFrames, this);
        }
    }

    void stopProcessing() {
        is_processing = false;
        for (auto& thread : processing_threads) {
            if (thread.joinable()) {
                thread.join();
            }
        }
    }

    void applyDynamicFilter(const cv::cuda::GpuMat& filter) {
        cv::cuda::multiply(gpu_frame, filter, gpu_frame);
    }

    void encodeToH265(const std::string& output_file) {
        cv::VideoWriter writer(output_file, cv::VideoWriter::fourcc('H', '2', '6', '5'), 
                              video_capture.get(cv::CAP_PROP_FPS), 
                              cv::Size(video_capture.get(cv::CAP_PROP_FRAME_WIDTH), 
                                      video_capture.get(cv::CAP_PROP_FRAME_HEIGHT)));
        cv::Mat frame;
        gpu_frame.download(frame);
        writer.write(frame);
        writer.release();
    }

    void streamOverRTP(const std::string& rtp_url) {
        cv::VideoWriter writer(rtp_url, cv::VideoWriter::fourcc('H', '2', '6', '5'), 
                              video_capture.get(cv::CAP_PROP_FPS), 
                              cv::Size(video_capture.get(cv::CAP_PROP_FRAME_WIDTH), 
                                      video_capture.get(cv::CAP_PROP_FRAME_HEIGHT)));
        cv::Mat frame;
        gpu_frame.download(frame);
        writer.write(frame);
        writer.release();
    }

    void addFrameToQueue(const cv::Mat& frame) {
        std::lock_guard<std::mutex> lock(queue_mutex);
        frame_queue.push(frame);
    }

    ~ImageProcessor() {
        stopProcessing();
        video_capture.release();
    }
};
