use rand::Rng;
use std::collections::HashMap;
use std::sync::{Arc, Mutex};

type Aes256Cbc = Cbc<Aes256, Pkcs7>;

pub struct SecureStorage {
    data: Arc<Mutex<HashMap<String, Vec<u8>>>>,
    key: [u8; 32],
    iv: [u8; 16],
}

impl SecureStorage {
    pub fn new(key: [u8; 32], iv: [u8; 16]) -> Self {
        SecureStorage {
            data: Arc::new(Mutex::new(HashMap::new())),
            key,
            iv,
        }
    }

    pub fn store_data(&self, key: String, value: &[u8]) -> Result<(), String> {
        let cipher = Aes256Cbc::new_from_slices(&self.key, &self.iv).map_err(|e| e.to_string())?;
        let mut buffer = vec![0; value.len() + 16];
        let pos = value.len();
        buffer[..pos].copy_from_slice(value);
        let encrypted = cipher.encrypt(&mut buffer, pos).map_err(|e| e.to_string())?;

        let mut data = self.data.lock().map_err(|e| e.to_string())?;
        data.insert(key, encrypted.to_vec());
        Ok(())
    }

    pub fn retrieve_data(&self, key: &str) -> Result<Vec<u8>, String> {
        let data = self.data.lock().map_err(|e| e.to_string())?;
        let encrypted = data.get(key).ok_or("Key not found")?;

        let cipher = Aes256Cbc::new_from_slices(&self.key, &self.iv).map_err(|e| e.to_string())?;
        let decrypted = cipher.decrypt_vec(encrypted).map_err(|e| e.to_string())?;
        Ok(decrypted)
    }

    pub fn delete_data(&self, key: &str) -> Result<(), String> {
        let mut data = self.data.lock().map_err(|e| e.to_string())?;
        data.remove(key).ok_or("Key not found")?;
        Ok(())
    }
}
