package FileManager

import (
	"errors"
	"io"
	"os"
	"sync"
)

type FileManager struct {
	storagePath string
	mu          sync.Mutex
}

func NewFileManager(storagePath string) *FileManager {
	return &FileManager{
		storagePath: storagePath,
	}
}

func (fm *FileManager) UploadFile(fileName string, fileData io.Reader) error {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	filePath := fm.storagePath + "/" + fileName
	file, err := os.Create(filePath)
	if err != nil {
		return err
	}
	defer file.Close()

	_, err = io.Copy(file, fileData)
	if err != nil {
		return err
	}

	return nil
}

func (fm *FileManager) DownloadFile(fileName string) (io.Reader, error) {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	filePath := fm.storagePath + "/" + fileName
	file, err := os.Open(filePath)
	if err != nil {
		return nil, err
	}

	return file, nil
}

func (fm *FileManager) DeleteFile(fileName string) error {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	filePath := fm.storagePath + "/" + fileName
	err := os.Remove(filePath)
	if err != nil {
		return err
	}

	return nil
}

func (fm *FileManager) FileExists(fileName string) (bool, error) {
	fm.mu.Lock()
	defer fm.mu.Unlock()

	filePath := fm.storagePath + "/" + fileName
	_, err := os.Stat(filePath)
	if err == nil {
		return true, nil
	}
	if errors.Is(err, os.ErrNotExist) {
		return false, nil
	}
	return false, err
}
