#include <iostream>
#include <fstream>
#include <vector>
#include <string>
#include <stdexcept>
#include <unordered_map>

class LogAnalyzer {
private:
    struct LogEntry {
        std::string timestamp;
        std::string severity;
        std::string message;
    };

    std::vector<LogEntry> logEntries;

public:
    void parseLog(const std::string& filePath) {
        std::ifstream logFile(filePath);
        if (!logFile.is_open()) {
            throw std::runtime_error("Failed to open log file: " + filePath);
        }

        std::string line;
        while (std::getline(logFile, line)) {
            LogEntry entry;
            size_t timestampEnd = line.find(' ');
            if (timestampEnd == std::string::npos) {
                continue; // Skip malformed lines
            }
            entry.timestamp = line.substr(0, timestampEnd);

            size_t severityStart = timestampEnd + 1;
            size_t severityEnd = line.find(' ', severityStart);
            if (severityEnd == std::string::npos) {
                continue; // Skip malformed lines
            }
            entry.severity = line.substr(severityStart, severityEnd - severityStart);

            size_t messageStart = severityEnd + 1;
            entry.message = line.substr(messageStart);

            logEntries.push_back(entry);
        }
        logFile.close();
    }

    std::vector<LogEntry> filterEntries(const std::string& severityFilter) {
        std::vector<LogEntry> filteredEntries;
        for (const auto& entry : logEntries) {
            if (entry.severity == severityFilter) {
                filteredEntries.push_back(entry);
            }
        }
        return filteredEntries;
    }

    void generateReport(const std::string& outputPath) {
        std::ofstream reportFile(outputPath);
        if (!reportFile.is_open()) {
            throw std::runtime_error("Failed to open report file: " + outputPath);
        }

        std::unordered_map<std::string, int> severityCounts;
        for (const auto& entry : logEntries) {
            severityCounts[entry.severity]++;
        }

        reportFile << "Log Report Summary\n";
        reportFile << "-----------------\n";
        for (const auto& pair : severityCounts) {
            reportFile << pair.first << ": " << pair.second << " entries\n";
        }

        reportFile.close();
    }
};
