use std::fs::File;
use std::io::{Read, Write};
use std::path::Path;
use std::sync::Arc;
use flate2::Compression;
use flate2::write::GzEncoder;
use flate2::read::GzDecoder;
use bzip2::write::BzEncoder;
use bzip2::read::BzDecoder;
use lz4::EncoderBuilder;
use lz4::Decoder;
use std::error::Error;
use std::sync::Mutex;

pub enum CompressionAlgorithm {
    Gzip,
    Bzip2,
    Lz4,
}

pub struct FileCompressor {
    algorithm: CompressionAlgorithm,
}

impl FileCompressor {
    pub fn new(algorithm: CompressionAlgorithm) -> Self {
        FileCompressor { algorithm }
    }

    pub fn compress_file(&self, input_path: &str, output_path: &str) -> Result<(), Box<dyn Error>> {
        let input_file = File::open(input_path)?;
        let output_file = File::create(output_path)?;

        match self.algorithm {
            CompressionAlgorithm::Gzip => {
                let mut encoder = GzEncoder::new(output_file, Compression::default());
                let mut buffer = Vec::new();
                input_file.take(u64::MAX).read_to_end(&mut buffer)?;
                encoder.write_all(&buffer)?;
                encoder.finish()?;
            }
            CompressionAlgorithm::Bzip2 => {
                let mut encoder = BzEncoder::new(output_file, bzip2::Compression::default());
                let mut buffer = Vec::new();
                input_file.take(u64::MAX).read_to_end(&mut buffer)?;
                encoder.write_all(&mut buffer)?;
                encoder.finish()?;
            }
            CompressionAlgorithm::Lz4 => {
                let mut encoder = EncoderBuilder::new().build(output_file)?;
                let mut buffer = Vec::new();
                input_file.take(u64::MAX).read_to_end(&mut buffer)?;
                encoder.write_all(&mut buffer)?;
                let (_output, result) = encoder.finish();
                result?;
            }
        }

        Ok(())
    }

    pub fn decompress_file(&self, input_path: &str, output_path: &str) -> Result<(), Box<dyn Error>> {
        let input_file = File::open(input_path)?;
        let output_file = File::create(output_path)?;

        match self.algorithm {
            CompressionAlgorithm::Gzip => {
                let mut decoder = GzDecoder::new(input_file);
                let mut buffer = Vec::new();
                decoder.read_to_end(&mut buffer)?;
                output_file.write_all(&buffer)?;
            }
            CompressionAlgorithm::Bzip2 => {
                let mut decoder = BzDecoder::new(input_file);
                let mut buffer = Vec::new();
                decoder.read_to_end(&mut buffer)?;
                output_file.write_all(&mut buffer)?;
            }
            CompressionAlgorithm::Lz4 => {
                let mut decoder = Decoder::new(input_file)?;
                let mut buffer = Vec::new();
                decoder.read_to_end(&mut buffer)?;
                output_file.write_all(&mut buffer)?;
            }
        }

        Ok(())
    }
}

// Thread-safe wrapper for concurrent operations
pub struct ConcurrentFileCompressor {
    compressor: Arc<Mutex<FileCompressor>>,
}

impl ConcurrentFileCompressor {
    pub fn new(algorithm: CompressionAlgorithm) -> Self {
        ConcurrentFileCompressor {
            compressor: Arc::new(Mutex::new(FileCompressor::new(algorithm))),
        }
    }

    pub fn compress_file(&self, input_path: &str, output_path: &str) -> Result<(), Box<dyn Error>> {
        let compressor = self.compressor.lock().unwrap();
        compressor.compress_file(input_path, output_path)
    }

    pub fn decompress_file(&self, input_path: &str, output_path: &str) -> Result<(), Box<dyn Error>> {
        let compressor = self.compressor.lock().unwrap();
        compressor.decompress_file(input_path, output_path)
    }
}
