import concurrent.futures
import json
import csv
import sqlite3
from abc import ABC, abstractmethod

class DataPipeline:
    def __init__(self):
        self.data_sources = {
            'csv': self._extract_csv,
            'json': self._extract_json,
            'database': self._extract_database
        }
        self.transformed_data = []

    def extract_data(self, source_type, source_path):
        if source_type not in self.data_sources:
            raise ValueError(f"Unsupported source type: {source_type}")
        return self.data_sources[source_type](source_path)

    def _extract_csv(self, file_path):
        with open(file_path, 'r') as file:
            reader = csv.DictReader(file)
            return [row for row in reader]

    def _extract_json(self, file_path):
        with open(file_path, 'r') as file:
            return json.load(file)

    def _extract_database(self, db_path):
        conn = sqlite3.connect(db_path)
        cursor = conn.cursor()
        cursor.execute("SELECT * FROM data")
        columns = [desc[0] for desc in cursor.description]
        data = [dict(zip(columns, row)) for row in cursor.fetchall()]
        conn.close()
        return data

    def transform_data(self, data, transform_func):
        with concurrent.futures.ThreadPoolExecutor() as executor:
            self.transformed_data = list(executor.map(transform_func, data))
        return self.transformed_data

    def load_data(self, destination, data=None):
        data = data or self.transformed_data
        if not data:
            raise ValueError("No data to load")

        if isinstance(destination, str):
            if destination.endswith('.csv'):
                self._load_csv(destination, data)
            elif destination.endswith('.json'):
                self._load_json(destination, data)
            else:
                raise ValueError("Unsupported destination format")
        else:
            self._load_database(destination, data)

    def _load_csv(self, file_path, data):
        with open(file_path, 'w', newline='') as file:
            writer = csv.DictWriter(file, fieldnames=data[0].keys())
            writer.writeheader()
            writer.writerows(data)

    def _load_json(self, file_path, data):
        with open(file_path, 'w') as file:
            json.dump(data, file, indent=4)

    def _load_database(self, db_path, data):
        conn = sqlite3.connect(db_path)
        cursor = conn.cursor()
        cursor.execute("CREATE TABLE IF NOT EXISTS data (id INTEGER PRIMARY KEY AUTOINCREMENT, data TEXT)")
        for record in data:
            cursor.execute("INSERT INTO data (data) VALUES (?)", (json.dumps(record),))
        conn.commit()
        conn.close()
