from typing import Dict, Any

class ParsedResponse:
    def __init__(self, data: Dict[str, Any]):
        self.data = data

class ApiClient:
    def __init__(self, base_url: str, api_key: str):
        self.base_url = base_url
        self.api_key = api_key
        self.session = requests.Session()
        self.session.headers.update({"Authorization": f"Bearer {self.api_key}"})

    def get_transaction_graph(self, transaction_id: str) -> ParsedResponse:
        endpoint = f"{self.base_url}/transaction-graph/{transaction_id}"
        response = self._request_with_backoff("GET", endpoint)
        return ParsedResponse(response.json())

    def post_smart_contract(self, contract_data: Dict[str, Any], abi: Dict[str, Any]) -> ParsedResponse:
        if not self._validate_abi(abi):
            raise ValueError("Invalid ABI")
        endpoint = f"{self.base_url}/smart-contract"
        payload = {"contract_data": contract_data, "abi": abi}
        response = self._request_with_backoff("POST", endpoint, json=payload)
        return ParsedResponse(response.json())

    def handle_rate_limiting(self, max_retries: int = 5) -> None:
        pass  # Handled in _request_with_backoff

    def _validate_abi(self, abi: Dict[str, Any]) -> bool:
        try:
            json.dumps(abi)
            return True
        except:
            return False

    def _request_with_backoff(self, method: str, url: str, **kwargs) -> requests.Response:
        max_retries = 5
        for attempt in range(max_retries):
            response = self.session.request(method, url, **kwargs)
            if response.status_code == 429:
                backoff_time = (2 ** attempt) * 0.1
                time.sleep(backoff_time)
                continue
            response.raise_for_status()
            return response
        raise Exception("Max retries exceeded")
