using System;
using System.Collections.Generic;
using System.Threading.Tasks;
using Confluent.Kafka;
using MessagePack;

namespace message_broker
{
    public class TopicRegistry
    {
        public const string INCOMING_TOPIC = "incoming-topic";
        public const string DEAD_LETTER_TOPIC = "dead-letter-topic";
        public const string RETRY_TOPIC = "retry-topic";
    }

    public enum ErrorCode
    {
        INVALID_PAYLOAD,
        PROCESSING_FAILURE,
        RETRY_EXHAUSTED
    }

    public class KafkaConfig
    {
        public string BootstrapServers { get; set; }
        public int RetryMaxAttempts { get; set; } = 3;
        public int RetryBackoffMs { get; set; } = 1000;
    }

    public static class serialization_handler
    {
        public static byte[] serialize_payload<T>(T payload)
        {
            return MessagePackSerializer.Serialize(payload);
        }

        public static T deserialize_payload<T>(byte[] data)
        {
            return MessagePackSerializer.Deserialize<T>(data);
        }
    }

    public class MessageBrokerService
    {
        private readonly IProducer<Null, byte[]> _producer;
        private readonly IConsumer<Null, byte[]> _consumer;
        private readonly KafkaConfig _kafkaConfig;

        public MessageBrokerService(KafkaConfig kafkaConfig)
        {
            _kafkaConfig = kafkaConfig;

            var producerConfig = new ProducerConfig { BootstrapServers = kafkaConfig.BootstrapServers };
            _producer = new ProducerBuilder<Null, byte[]>(producerConfig).Build();

            var consumerConfig = new ConsumerConfig
            {
                BootstrapServers = kafkaConfig.BootstrapServers,
                GroupId = "message-broker-group",
                AutoOffsetReset = AutoOffsetReset.Earliest
            };
            _consumer = new ConsumerBuilder<Null, byte[]>(consumerConfig).Build();
        }

        public async Task ProduceAsync(string topic, byte[] payload)
        {
            await _producer.ProduceAsync(topic, new Message<Null, byte[]> { Value = payload });
        }

        public void Consume(Action<byte[]> handler)
        {
            _consumer.Subscribe(TopicRegistry.INCOMING_TOPIC);

            while (true)
            {
                try
                {
                    var consumeResult = _consumer.Consume();
                    handler(consumeResult.Message.Value);
                }
                catch (ConsumeException e)
                {
                    Console.WriteLine($"Error consuming message: {e.Error.Reason}");
                }
            }
        }

        public async Task handle_dead_letter(byte[] payload, int retryCount, ErrorCode errorCode)
        {
            if (retryCount < _kafkaConfig.RetryMaxAttempts)
            {
                await Task.Delay(_kafkaConfig.RetryBackoffMs * (retryCount + 1));
                await ProduceAsync(TopicRegistry.RETRY_TOPIC, payload);
            }
            else
            {
                await ProduceAsync(TopicRegistry.DEAD_LETTER_TOPIC, payload);
                Console.WriteLine($"Message moved to dead letter. Error: {errorCode}");
            }
        }
    }
}
