import (
	"net"
	"sync"
	"time"
)

type network_monitor struct {
	active_connections map[string]net.Conn
	traffic_stats      map[string]uint64
	anomaly_logs       []string
	mutex              sync.Mutex
}

func NewNetworkMonitor() *network_monitor {
	return &network_monitor{
		active_connections: make(map[string]net.Conn),
		traffic_stats:      make(map[string]uint64),
		anomaly_logs:       make([]string, 0),
	}
}

func (nm *network_monitor) MonitorTraffic() {
	go func() {
		for {
			nm.mutex.Lock()
			// Simulate traffic monitoring
			for addr, conn := range nm.active_connections {
				nm.traffic_stats[addr] += uint64(time.Now().UnixNano() % 1024)
				_ = conn
			}
			nm.mutex.Unlock()
			time.Sleep(1 * time.Second)
		}
	}()
}

func (nm *network_monitor) DetectIntrusion() bool {
	nm.mutex.Lock()
	defer nm.mutex.Unlock()

	// Simulate intrusion detection logic
	for addr, traffic := range nm.traffic_stats {
		if traffic > 10000 {
			nm.anomaly_logs = append(nm.anomaly_logs, "High traffic from "+addr)
			return true
		}
	}
	return false
}

func (nm *network_monitor) LogActivity() []string {
	nm.mutex.Lock()
	defer nm.mutex.Unlock()
	return nm.anomaly_logs
