	count, exists := rl.requests[ip]
	if !exists {
		rl.requests[ip] = 1
		go func() {
			time.Sleep(rl.interval)
			delete(rl.requests, ip)
		}()
		return nil
	}
	if count >= rl.limit {
		return errors.New("rate limit exceeded")
	}
	rl.requests[ip]++
	return nil
}

func (as *auth_service) authenticate_user(token string) error {
	valid, exists := as.tokens[token]
	if !exists || !valid {
		return errors.New("invalid authentication token")
	}
	return nil
}
